import { useState, useEffect, useCallback, useRef, useMemo, Component } from "react";

class ErrorBoundary extends Component {
  constructor(props){super(props);this.state={error:null};}
  static getDerivedStateFromError(e){return{error:e};}
  render(){
    if(this.state.error)return(
      <div style={{padding:"40px 24px",color:"#e84040",fontFamily:"monospace",background:"#0a0a14",minHeight:"200px"}}>
        <div style={{fontSize:18,marginBottom:12}}>⚠️ Something crashed in this tab.</div>
        <div style={{fontSize:13,color:"#888",marginBottom:20}}>{this.state.error?.message}</div>
        <button onClick={()=>this.setState({error:null})} style={{padding:"8px 18px",background:"#e8c020",color:"#000",border:"none",borderRadius:6,cursor:"pointer",fontWeight:700}}>Try Again</button>
      </div>
    );
    return this.props.children;
  }
}


