const bmiCalc = (w,h) => { const m=h/100; return (w/(m*m)).toFixed(1); };
const tdeeCalc = (w,h,age,gender,act) => {
  const am={sedentary:1.2,light:1.375,moderate:1.55,active:1.725,veryActive:1.9};
  const bmr=gender==="male"?10*w+6.25*h-5*age+5:10*w+6.25*h-5*age-161;
  return Math.round(bmr*(am[act]||1.55));
};
const goalCals = (t,g) => g==="lose"?t-400:g==="gain"?t+350:t;
const macroSplit = (c,g) => {
  const [p,f,carb]=g==="lose"?[.38,.28,.34]:g==="gain"?[.30,.25,.45]:[.32,.30,.38];
  return {protein:Math.round(c*p/4),fat:Math.round(c*f/9),carbs:Math.round(c*carb/4)};
};
